import{_ as a,o,c as n,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"压缩","description":"","frontmatter":{"read_when":["你想了解自动压缩和 /compact","你正在调试长会话触及上下文限制的问题"],"summary":"上下文窗口 + 压缩：OpenSoul 如何将会话保持在模型限制内","title":"压缩","x-i18n":{"generated_at":"2026-02-01T20:22:17Z","model":"claude-opus-4-5","provider":"pi","source_hash":"e1d6791f2902044b5798ebf9320a7d055d37211eff4be03caa35d7e328ae803c","source_path":"concepts/compaction.md","workflow":14}},"headers":[],"relativePath":"zh-CN/concepts/compaction.md","filePath":"zh-CN/concepts/compaction.md","lastUpdated":null}'),t={name:"zh-CN/concepts/compaction.md"};function c(r,e,i,d,p,l){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="上下文窗口与压缩" tabindex="-1"><a class="header-anchor" href="#上下文窗口与压缩">#</a> 上下文窗口与压缩</h1><p>每个模型都有一个<strong>上下文窗口</strong>（可见的最大 token 数）。长时间运行的对话会累积消息和工具结果；一旦窗口空间紧张，OpenSoul 会<strong>压缩</strong>较早的历史记录以保持在限制范围内。</p><h2 id="什么是压缩" tabindex="-1"><a class="header-anchor" href="#什么是压缩">#</a> 什么是压缩</h2><p>压缩会将<strong>较早的对话总结</strong>为一条紧凑的摘要条目，并保持近期消息不变。摘要存储在会话历史中，因此后续请求使用的是：</p><ul><li>压缩摘要</li><li>压缩点之后的近期消息</li></ul><p>压缩会<strong>持久化</strong>到会话的 JSONL 历史记录中。</p><h2 id="配置" tabindex="-1"><a class="header-anchor" href="#配置">#</a> 配置</h2><p>有关 <code>agents.defaults.compaction</code> 设置，请参阅<a href="/docs/concepts/compaction">压缩配置与模式</a>。</p><h2 id="自动压缩-默认开启" tabindex="-1"><a class="header-anchor" href="#自动压缩-默认开启">#</a> 自动压缩（默认开启）</h2><p>当会话接近或超过模型的上下文窗口时，OpenSoul 会触发自动压缩，并可能使用压缩后的上下文重试原始请求。</p><p>你会看到：</p><ul><li>详细模式下显示 <code>🧹 Auto-compaction complete</code></li><li><code>/status</code> 显示 <code>🧹 Compactions: &lt;count&gt;</code></li></ul><p>在压缩之前，OpenSoul 可以运行一次<strong>静默记忆刷写</strong>轮次，将持久化笔记写入磁盘。详情及配置请参阅<a href="/docs/concepts/memory">记忆</a>。</p><h2 id="手动压缩" tabindex="-1"><a class="header-anchor" href="#手动压缩">#</a> 手动压缩</h2><p>使用 <code>/compact</code>（可选附带指令）强制执行一次压缩：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact Focus on decisions and open questions</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="上下文窗口来源" tabindex="-1"><a class="header-anchor" href="#上下文窗口来源">#</a> 上下文窗口来源</h2><p>上下文窗口因模型而异。OpenSoul 使用已配置提供商目录中的模型定义来确定限制。</p><h2 id="压缩与修剪" tabindex="-1"><a class="header-anchor" href="#压缩与修剪">#</a> 压缩与修剪</h2><ul><li><strong>压缩</strong>：总结并<strong>持久化</strong>到 JSONL 中。</li><li><strong>会话修剪</strong>：仅裁剪旧的<strong>工具结果</strong>，<strong>在内存中</strong>按请求进行。</li></ul><p>有关修剪的详情，请参阅 <a href="/docs/concepts/session-pruning">/concepts/session-pruning</a>。</p><h2 id="提示" tabindex="-1"><a class="header-anchor" href="#提示">#</a> 提示</h2><ul><li>当会话感觉过时或上下文臃肿时，使用 <code>/compact</code>。</li><li>大型工具输出已被截断；修剪可以进一步减少工具结果的堆积。</li><li>如果你需要全新开始，<code>/new</code> 或 <code>/reset</code> 会启动一个新的会话 ID。</li></ul>',23)])])}const m=a(t,[["render",c]]);export{u as __pageData,m as default};
